import{_ as t,o as e,c as a,Q as r}from"./chunks/framework.b67c47e6.js";const p=JSON.parse('{"title":"MOB v2 Machine File","description":"","frontmatter":{},"headers":[],"relativePath":"guide/machine_files/formats/panel_mob2/index.md","filePath":"guide/machine_files/formats/panel_mob2/index.md","lastUpdated":1773939149000}'),i={name:"guide/machine_files/formats/panel_mob2/index.md"},o=r('<h1 id="mob-v2-machine-file" tabindex="-1">MOB v2 Machine File <a class="header-anchor" href="#mob-v2-machine-file" aria-label="Permalink to &quot;MOB v2 Machine File&quot;">​</a></h1><p>The MOB v2 is an advanced panel assembly file format for the H&amp;M Mobi One V2 and Robobrick machines. It extends MOB v1 with dual-carriage support, flooring operations, and more granular tool control.</p><nav class="table-of-contents"><ul><li><a href="#output">Output</a></li><li><a href="#parameters">Parameters</a><ul><li><a href="#general">General</a></li><li><a href="#mill-directions">Mill Directions</a></li><li><a href="#tool-assignments">Tool Assignments</a></li><li><a href="#framing">Framing</a></li><li><a href="#robobrick-specific">Robobrick-Specific</a></li><li><a href="#isolation-specific">Isolation-Specific</a></li></ul></li></ul></nav><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><ul><li><strong>Format:</strong> ZIP containing <code>.mob2</code> files (one per assembly)</li><li><strong>Target machines:</strong> Mobi One V2, Robobrick, Isolation Machine</li></ul><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Machine zero mode</strong></td><td>Starting orientation — &#39;walls&#39; or &#39;floors&#39;.</td><td>walls</td></tr><tr><td><strong>Starting side</strong></td><td>Begin processing from &#39;inside&#39; or &#39;outside&#39; face.</td><td>inside</td></tr><tr><td><strong>Shift mode</strong></td><td>How operations shift between layers: &#39;No shift&#39;, &#39;Shift on layers&#39;, &#39;Shift on operations&#39;.</td><td>Shift on operations</td></tr><tr><td><strong>Trim operations</strong></td><td>Handling oversized operations: &#39;Trim to max size&#39;, &#39;Skip the layer&#39;, or &#39;Generate anyway&#39;.</td><td>Generate anyway</td></tr><tr><td><strong>Nailing pattern</strong></td><td>&#39;Regular pattern&#39;, &#39;Large panel pattern&#39;, or &#39;Single Nailing Optimized (BETA)&#39;.</td><td>Regular pattern</td></tr></tbody></table><h3 id="mill-directions" tabindex="-1">Mill Directions <a class="header-anchor" href="#mill-directions" aria-label="Permalink to &quot;Mill Directions&quot;">​</a></h3><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Negative zones outside</strong></td><td>Mill direction for outer negative zones.</td><td>Counter Clockwise</td></tr><tr><td><strong>Positive zones outside</strong></td><td>Mill direction for outer positive zones.</td><td>Clockwise</td></tr><tr><td><strong>Negative zones inside</strong></td><td>Mill direction for inner negative zones.</td><td>Clockwise</td></tr><tr><td><strong>Positive zones inside</strong></td><td>Mill direction for inner positive zones.</td><td>Counter Clockwise</td></tr></tbody></table><h3 id="tool-assignments" tabindex="-1">Tool Assignments <a class="header-anchor" href="#tool-assignments" aria-label="Permalink to &quot;Tool Assignments&quot;">​</a></h3><p>Configure which physical tool unit handles each operation, per zone (1–3) and side (inside/outside):</p><table><thead><tr><th>Tool type</th><th>Description</th><th>Default ID</th></tr></thead><tbody><tr><td><strong>Cladding nailer</strong></td><td>Nailer for plate fastening (per zone/side).</td><td>5</td></tr><tr><td><strong>Cladding screwer</strong></td><td>Screw driver for plates (per zone/side).</td><td>0 (disabled)</td></tr><tr><td><strong>Batten nailer</strong></td><td>Nailer for battens (per zone/side).</td><td>25</td></tr><tr><td><strong>Mill tool</strong></td><td>Milling/routing spindle.</td><td>28</td></tr><tr><td><strong>Saw tool</strong></td><td>Cross-cutting saw.</td><td>23</td></tr><tr><td><strong>Drill tool</strong></td><td>Drilling head.</td><td>22</td></tr><tr><td><strong>Glue tool</strong></td><td>Adhesive application.</td><td>29</td></tr></tbody></table><h3 id="framing" tabindex="-1">Framing <a class="header-anchor" href="#framing" aria-label="Permalink to &quot;Framing&quot;">​</a></h3><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Use custom matrix</strong></td><td>Use a custom nailing matrix instead of defaults.</td><td>Off</td></tr></tbody></table><h3 id="robobrick-specific" tabindex="-1">Robobrick-Specific <a class="header-anchor" href="#robobrick-specific" aria-label="Permalink to &quot;Robobrick-Specific&quot;">​</a></h3><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Optimized mode</strong></td><td>Use optimized brick placement sequencing.</td><td>On</td></tr><tr><td><strong>Join glue lines max distance</strong></td><td>Maximum distance (mm) to join adjacent glue lines.</td><td>100</td></tr><tr><td><strong>Export GID format</strong></td><td>IFC GID format: &#39;base64 (standard)&#39; or &#39;canonical UUID v4&#39;.</td><td>Standard</td></tr></tbody></table><h3 id="isolation-specific" tabindex="-1">Isolation-Specific <a class="header-anchor" href="#isolation-specific" aria-label="Permalink to &quot;Isolation-Specific&quot;">​</a></h3><table><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Export as CSV</strong></td><td>Export isolation data as CSV instead of MOB format.</td><td>Off</td></tr></tbody></table>',19),n=[o];function d(s,l,h,c,g,m){return e(),a("div",null,n)}const u=t(i,[["render",d]]);export{p as __pageData,u as default};
